78	// ── TableFlags ─────────────────────────────────────────────────────────────────
79	
80	/// Bitfield for a [`LuaTable`]: lower bits record absent fast-access metamethods;
81	/// bit 7 (`BIT_RAS`) encodes whether `alimit` is the real array size.
82	///
83	/// C: `lu_byte flags` in `Table`.  Uses per-PORTING.md §4.9 Tag-style newtype.
84	#[derive(Clone, Copy, Debug, Default)]
85	pub struct TableFlags(pub u8);
86	
87	impl TableFlags {
88	    /// `isrealasize(t)` — bit 7 clear means alimit IS the real array size.
89	    #[inline]
90	    pub fn is_real_asize(self) -> bool {
91	        (self.0 & BIT_RAS) == 0
92	    }
93	
94	    /// `setrealasize(t)` — clear BIT_RAS so alimit becomes the canonical size.
95	    #[inline]
96	    pub fn set_real_asize(&mut self) {
97	        self.0 &= !BIT_RAS;
98	    }
99	
100	    /// `setnorealasize(t)` — set BIT_RAS so alimit is only a hint.
101	    #[inline]
102	    pub fn set_no_real_asize(&mut self) {
103	        self.0 |= BIT_RAS;
104	    }
105	
106	    /// `invalidateTMcache(t)` — clear all fast-access metamethod bits.
107	    /// Forces the next access to look up the metatable properly.
108	    /// C: `(t)->flags &= ~maskflags`
109	    /// TODO(port): MASK_FLAGS depends on TM_EQ ordinal from ltm.h; using 0x7F placeholder.
110	    #[inline]
111	    pub fn invalidate_tm_cache(&mut self) {
112	        // maskflags = (1 << (TM_EQ + 1)) - 1; TM_EQ = 6 in Lua 5.4 → 0x7F
113	        const MASK_FLAGS: u8 = 0x7F;
114	        self.0 &= !MASK_FLAGS;
115	    }
116	}
