120	/// One node in a table's hash part.
121	///
122	/// C: `Node` (= `struct Node` composed of `NodeKey` + `TValue i_val`).
123	/// The C struct uses a union `{key_tt, key_val, next}` packed for layout;
124	/// in Rust we use plain named fields.  The GC color / "dead key" flag is
125	/// present in C but elided in Phases A–C (no tracing GC yet).
126	pub struct TableNode {
127	    /// Value stored at this key.  C: `n->i_val` / `gval(n)`.
128	    pub value: LuaValue,
129	    /// Key stored in this node.  C: `n->u.key_val` + `n->u.key_tt`.
130	    pub key: LuaValue,
131	    /// Collision-chain offset (positive = next is `self + next`, negative allowed).
132	    /// Zero means end of chain.  C: `n->u.next` (`int`).
133	    pub next: i32,
