pub fn slot_value(&self, slot: TableSlotRef) -> LuaValue {
    match slot {
        TableSlotRef::Array(i) => self.array[i].clone(),
        TableSlotRef::Hash(i) => self.node[i].value.clone(),
        TableSlotRef::Absent => LuaValue::Nil,
    }
